      "content": "const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

const projectsStore = {};

function addMember(projectId, userId, role) {
  if (!userId || !role) {
    return null;
  }
  const project = projectsStore[projectId] || { members: [] };
  const existingMember = project.members.find(member => member.userId === userId);
  if (existingMember) {
    return 'duplicate';
  }
  project.members.push({ userId, role });
  projectsStore[projectId] = project;
  return project;
}

function getMembers(projectId) {
  const project = projectsStore[projectId] || { members: [] };
  return project.members;
}

module.exports = {
  addMember,
  getMembers,
};
