      "content": "const router = require('express').Router();
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

router.get('/', (req, res) => {
  const projects = projectsService.getProjects();
  res.json({ projects });
});

router.post('/', (req, res) => {
  const name = String(req.body?.name || '').trim();
  if (!name) return sendError(res, 400, 'BAD_REQUEST', 'Name is required');
  const project = projectsService.createProject(name);
  res.status(201).json({ project });
});

router.get('/:projectId', (req, res) => {
  const projectId = req.params.projectId;
  const project = projectsService.getProject(projectId);
  if (!project) return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  res.json({ project });
});

module.exports = router;
